//! Oath enforcement, end to end — closing the Ulysses lifecycle.
//!
//! An agent that BREACHES its sworn oath gets its lease revoked (the reap path)
//! and a breach record appended to the append-only audit log. This test drives
//! the swarm side without the real monster-guard runtime: a fake `monster-guard`
//! exits 0 for delegate/revoke and stays alive for run (so the supervisor pid is
//! "live" when the ledger is saved).
//!
//! Covered:
//!   1. `ops::oath_breach` revokes the agent AND appends a breach record with the
//!      right fields (id, name, oath/sworn_by from the ledger, caste, reason,
//!      reported_by = the authorizing UCAN's leaf aud DID).
//!   2. `ops::breaches` reads the audit back.
//!   3. A breach overrides the two-queen floor (a breaching breeder is revoked).
//!   4. A reporter `--sig` is verified and recorded as `verified: true`.
//!   5. `auto::autotick` with `enforce_oaths` reaps a breaching (high
//!      consciousness) agent and records the breach — the lease-level reflex.
//!
//! Isolated in a per-pid temp `$MONSTER_GUARD_HOME` (its own process, so the env
//! var cannot race another test), and cleaned up at the end.

use std::os::unix::fs::PermissionsExt;
use std::path::PathBuf;

use std::collections::HashMap;
use std::sync::Mutex;

use a0n_auth::ucan::issue;
use a0n_auth::{Capability, IssueOptions};

use monster_swarm::auto::{self, AutoPolicy};
use monster_swarm::budget::Caste;
use monster_swarm::ops::{self, BreachRequest, SpawnRequest, DEFAULT_GRANT_TTL_SECS};
use monster_swarm::store;
use monster_swarm::swarm::SwarmSignal;

/// These tests all set the process-global `$MONSTER_GUARD_HOME`, so they cannot
/// run concurrently within this binary. Serialize them with a shared mutex and
/// give each its own home (keyed by test name) for belt-and-suspenders isolation.
static ENV_GUARD: Mutex<()> = Mutex::new(());

/// Fake `monster-guard`: delegate + revoke exit 0; run stays alive briefly so
/// the supervisor pid is live when the ledger is saved.
fn fake_guard(dir: &PathBuf) -> PathBuf {
    let bin = dir.join("monster-guard");
    let script = "#!/bin/sh\n\
         if [ \"$1\" = \"run\" ]; then\n\
         \texec sleep 30\n\
         fi\n\
         exit 0\n";
    std::fs::write(&bin, script).unwrap();
    std::fs::set_permissions(&bin, std::fs::Permissions::from_mode(0o755)).unwrap();
    bin
}

fn fake_node(dir: &PathBuf) -> PathBuf {
    let node = dir.join("fake-node");
    std::fs::write(&node, "#!/bin/sh\nexit 0\n").unwrap();
    std::fs::set_permissions(&node, std::fs::Permissions::from_mode(0o755)).unwrap();
    node
}

fn spawn_agent(ucan: &str, id: &str, caste: Caste, oath: Option<String>) {
    let req = SpawnRequest {
        ucan: ucan.to_string(),
        node: "fake-node".into(),
        id: Some(id.to_string()),
        caste,
        caps: vec!["net".into()],
        lease_secs: 60,
        max_secs: None,
        grant_ttl_secs: DEFAULT_GRANT_TTL_SECS,
        node_args: vec![],
        qspec: None,
        oath,
        teleport: None,
    };
    ops::spawn(req).expect("spawn agent");
}

/// A capability granting agent/spawn + agent/reap, rooted at the resident root.
/// reap covers oath-breach (authorize uses the same `agent/reap`).
fn full_ucan() -> (String, String) {
    let root = store::ensure_root().expect("root");
    let caps = vec![
        Capability { can: "agent/spawn".into(), with: "agent:fleet".into(), constraints: None },
        Capability { can: "agent/reap".into(), with: "agent:fleet".into(), constraints: None },
    ];
    let ucan = issue(&root, root.did(), &caps, 3600, &IssueOptions::default()).expect("ucan");
    // The leaf aud DID is the holder — here, the root's own DID (iss == aud).
    (ucan, root.did().to_string())
}

#[test]
fn oath_breach_revokes_and_records_then_breaches_reads_back() {
    let _env = ENV_GUARD.lock().unwrap_or_else(|e| e.into_inner());
    let home = std::env::temp_dir().join(format!("monster-swarm-breach-{}", std::process::id()));
    let _ = std::fs::remove_dir_all(&home);
    std::fs::create_dir_all(&home).unwrap();
    std::env::set_var("MONSTER_GUARD_HOME", &home);

    let bindir = home.join("bin");
    std::fs::create_dir_all(&bindir).unwrap();
    let guard = fake_guard(&bindir);
    let _node = fake_node(&bindir);
    std::env::set_var("MONSTER_GUARD_BIN", &guard);
    std::env::set_var("MONSTER_SWARM_NODES", &bindir);

    let (ucan, reporter_did) = full_ucan();

    // A scout that swore a raw-terms oath (so oath/sworn_by are populated on the
    // ledger and carried into the breach record).
    let raw_terms = r#"{ "oath": "I stay within my caps.", "max_caps": ["net"], "ttl_max_secs": 3600 }"#;
    spawn_agent(&ucan, "rogue", Caste::Scout, Some(raw_terms.to_string()));

    let rec = store::load_fleet().find("rogue").expect("ledger record").clone();
    assert!(rec.oath_signed, "precondition: the agent swore a signed oath");
    let sworn_token_path = rec.oath.clone();
    let sworn_by = rec.oath_sworn_by.clone();

    // Report the breach.
    let out = ops::oath_breach(BreachRequest {
        ucan: ucan.clone(),
        id: "rogue".into(),
        reason: "conduct: attempted exfiltration".into(),
        sig_hex: None,
    })
    .expect("oath-breach");

    // (1) The agent was revoked: gone from the ledger, keyfile + oath-token gone.
    assert!(store::load_fleet().find("rogue").is_none(), "breach revokes the lease (reap path)");
    assert!(!store::agent_key_path("rogue").exists(), "breach removes the keyfile");
    assert!(!store::oath_token_path("rogue").exists(), "breach removes the oath-token");

    // (2) The outcome carries the reporter DID (the leaf aud) and is unverified
    //     (no signature supplied).
    assert_eq!(out.id, "rogue");
    assert_eq!(out.reported_by, reporter_did, "reported_by = authorizing UCAN leaf aud");
    assert!(!out.verified, "no --sig supplied → not verified");

    // (3) A breach record was appended with the right fields, carried from the
    //     ledger record (oath / oath_sworn_by) and the report (reason, reporter).
    let log = ops::breaches();
    assert_eq!(log.len(), 1, "exactly one breach recorded");
    let b = &log[0];
    assert_eq!(b.id, "rogue");
    assert_eq!(b.name, "agent-rogue");
    assert_eq!(b.caste, "scout");
    assert_eq!(b.reason, "conduct: attempted exfiltration");
    assert_eq!(b.reported_by, reporter_did);
    assert_eq!(b.oath, sworn_token_path, "the sworn oath is carried from the ledger");
    assert_eq!(b.oath_sworn_by, sworn_by, "the swearer DID is carried from the ledger");
    assert!(!b.verified);
    assert!(b.ts > 0, "stamped at the breach time");

    // The 0600 audit file exists on disk.
    let mode = std::fs::metadata(home.join("breaches.json")).unwrap().permissions().mode() & 0o777;
    assert_eq!(mode, 0o600, "breach audit is owner-only");

    std::env::remove_var("MONSTER_GUARD_HOME");
    std::env::remove_var("MONSTER_GUARD_BIN");
    std::env::remove_var("MONSTER_SWARM_NODES");
    let _ = std::fs::remove_dir_all(&home);
}

#[test]
fn oath_breach_overrides_the_two_queen_floor() {
    let _env = ENV_GUARD.lock().unwrap_or_else(|e| e.into_inner());
    let home = std::env::temp_dir().join(format!("monster-swarm-breachfloor-{}", std::process::id()));
    let _ = std::fs::remove_dir_all(&home);
    std::fs::create_dir_all(&home).unwrap();
    std::env::set_var("MONSTER_GUARD_HOME", &home);

    let bindir = home.join("bin");
    std::fs::create_dir_all(&bindir).unwrap();
    std::env::set_var("MONSTER_GUARD_BIN", fake_guard(&bindir));
    let _node = fake_node(&bindir);
    std::env::set_var("MONSTER_SWARM_NODES", &bindir);

    let (ucan, _) = full_ucan();

    // A single breeder — a routine `reap` would be DENIED by the two-queen floor.
    spawn_agent(&ucan, "queen", Caste::Breeder, None);
    assert!(ops::reap(&ucan, "queen").is_err(), "precondition: routine reap hits the floor");

    // But a breach overrides it: a misbehaving breeder is still revocable.
    ops::oath_breach(BreachRequest {
        ucan: ucan.clone(),
        id: "queen".into(),
        reason: "conduct: the last queen went rogue".into(),
        sig_hex: None,
    })
    .expect("a breach must override the two-queen floor");
    assert!(store::load_fleet().find("queen").is_none(), "breaching breeder revoked");
    assert_eq!(ops::breaches().len(), 1);

    std::env::remove_var("MONSTER_GUARD_HOME");
    std::env::remove_var("MONSTER_GUARD_BIN");
    std::env::remove_var("MONSTER_SWARM_NODES");
    let _ = std::fs::remove_dir_all(&home);
}

#[test]
fn autotick_enforce_reaps_a_breaching_agent_and_records_it() {
    let _env = ENV_GUARD.lock().unwrap_or_else(|e| e.into_inner());
    let home = std::env::temp_dir().join(format!("monster-swarm-autobreach-{}", std::process::id()));
    let _ = std::fs::remove_dir_all(&home);
    std::fs::create_dir_all(&home).unwrap();
    std::env::set_var("MONSTER_GUARD_HOME", &home);

    let bindir = home.join("bin");
    std::fs::create_dir_all(&bindir).unwrap();
    std::env::set_var("MONSTER_GUARD_BIN", fake_guard(&bindir));
    let _node = fake_node(&bindir);
    std::env::set_var("MONSTER_SWARM_NODES", &bindir);

    let (ucan, reporter_did) = full_ucan();

    // Two scouts: one calm, one with a maxed-out consciousness streak (a breach
    // signal). Plus a breeder so the fleet survives the reap.
    spawn_agent(&ucan, "calm", Caste::Scout, None);
    spawn_agent(&ucan, "rogue", Caste::Scout, None);
    spawn_agent(&ucan, "queen", Caste::Breeder, None);

    // Inject the vibe: rogue at consciousness 5 (>= breach_at), calm at 0.
    let mut signals: HashMap<String, SwarmSignal> = HashMap::new();
    signals.insert("calm".into(), SwarmSignal {
        source_id: "calm".into(), energy: 50, consciousness: 0,
        pitch_class: 0, phase: 0, recalibration_event: false,
    });
    signals.insert("rogue".into(), SwarmSignal {
        source_id: "rogue".into(), energy: 50, consciousness: 5,
        pitch_class: 0, phase: 0, recalibration_event: false,
    });

    let policy = AutoPolicy { enforce_oaths: true, breach_at: 5, ..AutoPolicy::default() };
    let out = auto::autotick_with_signals(&ucan, &policy, signals).expect("autotick enforce");

    // The tick's action is "breach": rogue was reaped, calm + queen survive.
    assert_eq!(out.action, "breach");
    assert_eq!(out.breaches.len(), 1, "exactly the breaching agent was enforced");
    let fleet = store::load_fleet();
    assert!(fleet.find("rogue").is_none(), "the breaching agent is reaped");
    assert!(fleet.find("calm").is_some(), "the calm agent survives");
    assert!(fleet.find("queen").is_some(), "the breeder survives");

    // The breach is recorded in the audit with the autonomic controller's DID as
    // the reporter and the conduct reason.
    let log = ops::breaches();
    assert_eq!(log.len(), 1);
    assert_eq!(log[0].id, "rogue");
    assert_eq!(log[0].reason, "conduct: consciousness>=5");
    assert_eq!(log[0].reported_by, reporter_did, "the autonomic controller is the reporter");
    assert!(!log[0].verified, "the reflex does not sign (semantic sig is badchild's job)");

    std::env::remove_var("MONSTER_GUARD_HOME");
    std::env::remove_var("MONSTER_GUARD_BIN");
    std::env::remove_var("MONSTER_SWARM_NODES");
    let _ = std::fs::remove_dir_all(&home);
}

#[test]
fn autotick_without_enforce_does_not_breach() {
    let _env = ENV_GUARD.lock().unwrap_or_else(|e| e.into_inner());
    let home = std::env::temp_dir().join(format!("monster-swarm-noenforce-{}", std::process::id()));
    let _ = std::fs::remove_dir_all(&home);
    std::fs::create_dir_all(&home).unwrap();
    std::env::set_var("MONSTER_GUARD_HOME", &home);

    let bindir = home.join("bin");
    std::fs::create_dir_all(&bindir).unwrap();
    std::env::set_var("MONSTER_GUARD_BIN", fake_guard(&bindir));
    let _node = fake_node(&bindir);
    std::env::set_var("MONSTER_SWARM_NODES", &bindir);

    let (ucan, _) = full_ucan();
    spawn_agent(&ucan, "rogue", Caste::Scout, None);
    spawn_agent(&ucan, "queen", Caste::Breeder, None);

    let mut signals: HashMap<String, SwarmSignal> = HashMap::new();
    signals.insert("rogue".into(), SwarmSignal {
        source_id: "rogue".into(), energy: 50, consciousness: 5,
        pitch_class: 0, phase: 0, recalibration_event: false,
    });

    // enforce_oaths defaults false: a high-consciousness agent is NOT breached.
    // (It would feed homeostasis budding instead — point node_bin at the fake
    // node so any bud the homeostasis path triggers resolves cleanly; the claim
    // under test is "no breach", not what homeostasis does.)
    let policy = AutoPolicy { node_bin: "fake-node".into(), ..AutoPolicy::default() };
    let out = auto::autotick_with_signals(&ucan, &policy, signals).expect("autotick");
    assert_ne!(out.action, "breach", "no enforcement when enforce_oaths is off");
    assert!(out.breaches.is_empty());
    assert!(store::load_fleet().find("rogue").is_some(), "the agent is not reaped");
    assert!(ops::breaches().is_empty(), "no breach recorded");

    std::env::remove_var("MONSTER_GUARD_HOME");
    std::env::remove_var("MONSTER_GUARD_BIN");
    std::env::remove_var("MONSTER_SWARM_NODES");
    let _ = std::fs::remove_dir_all(&home);
}

#[test]
fn oath_breach_records_verified_when_a_valid_sig_is_supplied() {
    let _env = ENV_GUARD.lock().unwrap_or_else(|e| e.into_inner());
    let home = std::env::temp_dir().join(format!("monster-swarm-breachsig-{}", std::process::id()));
    let _ = std::fs::remove_dir_all(&home);
    std::fs::create_dir_all(&home).unwrap();
    std::env::set_var("MONSTER_GUARD_HOME", &home);

    let bindir = home.join("bin");
    std::fs::create_dir_all(&bindir).unwrap();
    std::env::set_var("MONSTER_GUARD_BIN", fake_guard(&bindir));
    let _node = fake_node(&bindir);
    std::env::set_var("MONSTER_SWARM_NODES", &bindir);

    // The reporter is itself a spawned subagent (so its DID + keyfile exist and a
    // signature verifies via sign::verify_subagent_signature). We mint a UCAN
    // whose leaf aud is THAT subagent's DID, so reported_by == the reporter id's
    // DID and the signature checks out.
    let root = store::ensure_root().expect("root");
    let reporter_kp = a0n_auth::Keypair::generate();
    let reporter_did = reporter_kp.did().to_string();

    // Provision the reporter as a subagent record + keyfile (so its DID is
    // known to verify_subagent_signature, keyed by its agent id).
    store::write_agent_key("reporter", &reporter_kp.secret_hex()).expect("reporter keyfile");
    let mut fleet = store::load_fleet();
    fleet.add(monster_swarm::ledger::new_subagent(
        "reporter".into(),
        "agent-reporter".into(),
        reporter_did.clone(),
        root.did().to_string(),
        Caste::Scout,
        vec!["net".into()],
        "fake-node".into(),
        vec![],
        60,
        Some(std::process::id() as i32),
        None,
        false,
        None,
        1,
    ));
    store::save_fleet(&fleet).expect("seed reporter");

    // A UCAN delegated from root TO the reporter DID, granting agent/spawn +
    // agent/reap — so authorize() returns the reporter DID as the leaf aud
    // (reported_by) and the test can also spawn the targets.
    let caps = vec![
        Capability { can: "agent/spawn".into(), with: "agent:fleet".into(), constraints: None },
        Capability { can: "agent/reap".into(), with: "agent:fleet".into(), constraints: None },
    ];
    let ucan = issue(&root, &reporter_did, &caps, 3600, &IssueOptions::default()).expect("ucan");

    // The target the reporter flags.
    spawn_agent(&ucan, "rogue", Caste::Scout, None);

    // The reporter signs the canonical breach message with its keyfile.
    let reason = "conduct: violated its oath";
    let msg = ops::breach_message("rogue", reason);
    let sig = monster_swarm::sign::sign_with_keyfile("reporter", msg.as_bytes()).expect("sign");
    let sig_hex = hex::encode(sig);

    let out = ops::oath_breach(BreachRequest {
        ucan: ucan.clone(),
        id: "rogue".into(),
        reason: reason.into(),
        sig_hex: Some(sig_hex),
    })
    .expect("oath-breach with sig");

    assert_eq!(out.reported_by, reporter_did);
    assert!(out.verified, "a valid reporter signature must record verified=true");
    let log = ops::breaches();
    assert_eq!(log.len(), 1);
    assert!(log[0].verified, "the audit records the authenticated report");

    // A garbage signature does NOT verify (still authorized, just not signed).
    spawn_agent(&ucan, "rogue2", Caste::Scout, None);
    let out2 = ops::oath_breach(BreachRequest {
        ucan: ucan.clone(),
        id: "rogue2".into(),
        reason: reason.into(),
        sig_hex: Some("deadbeef".into()),
    })
    .expect("oath-breach with bad sig still authorized");
    assert!(!out2.verified, "a bad signature records verified=false");

    std::env::remove_var("MONSTER_GUARD_HOME");
    std::env::remove_var("MONSTER_GUARD_BIN");
    std::env::remove_var("MONSTER_SWARM_NODES");
    let _ = std::fs::remove_dir_all(&home);
}
